10	/**
11	 * Intercept /graphql and respond with mock data based on query type.
12	 */
13	async function mockGraphQL(
14		page: import('@playwright/test').Page,
15		nodeInfo = NODE_INFO,
16		projects = PROJECTS
17	) {
18		await page.route('/graphql', async (route) => {
19			const body = route.request().postDataJSON() as { query: string };
20			if (body.query.includes('NodeInfo')) {
21				await route.fulfill({
22					status: 200,
23					contentType: 'application/json',
24					body: JSON.stringify({ data: { nodeInfo } })
25				});
26			} else if (body.query.includes('Projects')) {
27				await route.fulfill({
28					status: 200,
29					contentType: 'application/json',
30					body: JSON.stringify({
31						data: { projects: { edges: projects.map((p) => ({ node: p })) } }
32					})
33				});
34			} else {
35				await route.continue();
36			}
37		});
38	}
